const express = require('express');
const { MongoClient } = require('mongodb');

const app = express();
app.use(express.json());

const MONGODB_URI = 'mongodb://localhost:27017'; // Replace with your MongoDB connection string
const DB_NAME = 'yourDatabaseName'; // Replace with your database name
const COLLECTION_NAME = 'yourCollectionName'; // Replace with your collection name

let db;

async function connectToMongo() {
  try {
    const client = new MongoClient(MONGODB_URI);
    await client.connect();
    db = client.db(DB_NAME);
    console.log('Connected to MongoDB');
  } catch (error) {
    console.error('Failed to connect to MongoDB:', error);
    process.exit(1); // Exit if MongoDB connection fails
  }
}

// Endpoint to query data
app.post('/query', async (req, res) => {
  const { filter = {}, projection = {}, sort = {}, limit = 0, skip = 0 } = req.body;

  if (!db) {
    return res.status(500).json({ error: 'MongoDB not connected.' });
  }

  try {
    const collection = db.collection(COLLECTION_NAME);

    // Apply MongoDB find operations directly
    let cursor = collection.find(filter);

    if (Object.keys(projection).length > 0) {
      cursor = cursor.project(projection);
    }

    if (Object.keys(sort).length > 0) {
      cursor = cursor.sort(sort);
    }

    if (limit > 0) {
      cursor = cursor.limit(limit);
    }

    if (skip > 0) {
      cursor = cursor.skip(skip);
    }

    const results = await cursor.toArray();
    res.json(results);

  } catch (error) {
    console.error('Error querying MongoDB:', error);
    res.status(500).json({ error: 'Failed to query data', details: error.message });
  }
});

const PORT = process.env.PORT || 3000;

connectToMongo().then(() => {
  app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
    console.log(`Access query endpoint: POST http://localhost:${PORT}/query`);
  });
});